"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[341],{94527:e=>{e.exports=JSON.parse('{"functions":[{"name":"set","desc":"Attach a single field to the span. Returns the span for chaining.","params":[],"returns":[],"function_type":"method","source":{"line":63,"path":"modules/wide-logger/init.luau"}},{"name":"merge","desc":"Attach a table of fields to the span at once. Existing keys are\\noverwritten. Returns the span for chaining.","params":[],"returns":[],"function_type":"method","source":{"line":77,"path":"modules/wide-logger/init.luau"}},{"name":"fail","desc":"Mark the span as failed and attach the given error. The span will be\\nemitted via `warn` when finished. Returns the span for chaining.","params":[],"returns":[],"function_type":"method","source":{"line":93,"path":"modules/wide-logger/init.luau"}},{"name":"finish","desc":"Emit the wide event. Subsequent calls are no-ops. After this, calls to\\n`set`/`merge`/`fail` are also no-ops.","params":[],"returns":[],"function_type":"method","source":{"line":156,"path":"modules/wide-logger/init.luau"}},{"name":"span","desc":"Open a new span. Set fields on it as the operation progresses, then\\ncall `:finish()` to emit the wide event.","params":[],"returns":[],"function_type":"static","source":{"line":180,"path":"modules/wide-logger/init.luau"}},{"name":"withSpan","desc":"Open a span, run `fn(span)`, and finish the span automatically. If\\n`fn` errors, the span is marked failed and the error is rethrown\\nafter the event is emitted. Returns whatever `fn` returned on success.","params":[],"returns":[],"function_type":"static","source":{"line":205,"path":"modules/wide-logger/init.luau"}}],"properties":[],"types":[],"name":"WideLogger","desc":"A logger built around \\"wide events\\" (https://loggingsucks.com/): one\\nstructured event per operation, enriched with context as the operation\\nruns, emitted exactly once when the span finishes.\\n\\nInstead of scattering `print` calls across a code path, you open a span\\nat the start of an operation, attach high-cardinality context fields\\n(user ids, request ids, business state) along the way, and let the\\nlogger emit a single readable record at the end.\\n\\n```lua\\nlocal Log = require(path.to.WideLogger)\\n\\nLog.withSpan(\\"checkout.process\\", { request_id = id }, function(span)\\n    span:set(\\"user_id\\", user.Id)\\n    span:set(\\"cart_total_cents\\", cart.totalCents)\\n    -- ... do work; if this errors the span auto-fails ...\\n    span:set(\\"payment_provider\\", \\"stripe\\")\\nend)\\n```\\n\\nOutput goes to `print` (ok) or `warn` (failed) and is formatted for\\nStudio readability:\\n\\n```\\n[checkout.process] OK 142.30ms\\n  cart_total_cents = 4200\\n  payment_provider = \\"stripe\\"\\n  request_id = \\"abc\\"\\n  user_id = 5\\n```","source":{"line":36,"path":"modules/wide-logger/init.luau"}}')}}]);